  ('diplomatic-456f2445-moex-00552', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-111-c655adf3', 'sub-diplomatic-456f2445-05', NULL, 'single_choice', '1982年8月17日，時任美國國務卿喬治．舒茲發送給時任美國在臺協會處長李潔明，該電報揭示「對 臺六項保證」，下列何者不是六項保證的內容？', '["未同意設定終止對臺軍售的日期", "未同意就對臺軍售議題向中華人民共和國徵詢意見", "未改變關於臺灣主權的立場", "未改變要求臺灣與中華人民共和國進行和平談判"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:22+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00553', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-111-c655adf3', 'sub-diplomatic-456f2445-05', NULL, 'single_choice', '根據中國大陸的黨政體制，下列那一個單位不是「國務院台灣事務辦公室」直屬事業單位？', '["信息中心", "海峽兩岸關係研究中心", "海峽兩岸交流中心", "全國臺灣研究會"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:22+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00554', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-111-c655adf3', 'sub-diplomatic-456f2445-05', NULL, 'single_choice', '英國首相強生（BorisJohnson）在數十位閣員辭職施壓下，2022年7月7日發表聲明，先辭去保守黨黨 魁職務，9月才會辭去首相，並宣布任命新內閣成員，引起黨內外爭議。請問強生為何要9月才辭首相？', '["保守黨要到9月選舉黨魁", "女王慰留", "國會要到9月重新改選", "烏俄戰爭要到9月才會有結果"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:22+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00555', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-111-c655adf3', 'sub-diplomatic-456f2445-05', NULL, 'single_choice', '日本於2022年7月10日舉行參議院選舉，由自民黨、公明黨、日本維新會、國民民主黨四黨形成的「修 憲勢力」掌握177席，請問此席位數有何特殊意義？', '["自民黨繼續執政，自行提出修憲創議", "超越參議院3/4席次，該勢力可以提出修憲創議", "結合眾議院原掌握的超越2/3席次，共同提出修憲創議", "日本憲法是由當年聯合國駐日盟軍總司令部指導完成，修憲創議需送交聯合國審議"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:22+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00556', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-111-c655adf3', 'sub-diplomatic-456f2445-05', NULL, 'single_choice', '下列何國的總統選舉參選年齡限制最低？', '["法國", "美國", "中華民國", "韓國"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:22+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00557', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-111-c655adf3', 'sub-diplomatic-456f2445-05', NULL, 'single_choice', '比較政治研究學者以政治系統（politicalsystem）取代國家（state）概念，藉以發展科學的理論，下述 何者最接近事實？', '["解決了過往關於決策體系不透明的問題", "受到行為主義影響，發展通則化理論", "由於更加科學，所以適用在所有政體類型國家", "主張政治體系是一個從輸入、系統輸出到回饋的閉鎖行動系統"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:22+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00558', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-111-c655adf3', 'sub-diplomatic-456f2445-05', NULL, 'single_choice', '美國聯邦最高法院常被外界以「保守派」與「自由派」說明其成員的意識形態取向，2022年聯邦最高 法院推翻1973年「羅伊控訴韋德案」（Roev.Wade）保障墮胎權的歷史性裁決，以及判決紐約州限制 人民攜槍出家門的法律違憲，人民享有在公共場所攜帶手槍的基本權利。下述何者正確？', '["1973年「羅伊控訴韋德案」保障墮胎權是保守派大法官為多數的判決", "2022年推翻1973年「羅伊控訴韋德案」是自由派大法官為多數的判決", "2022年判決紐約州限制人民攜槍出家門的法律違憲，是保守派大法官為多數的判決", "美國聯邦最高法院由9名大法官組成，任期為8年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:22+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00559', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-111-c655adf3', 'sub-diplomatic-456f2445-05', NULL, 'single_choice', '2019年1月4日總統令公布之《憲法訴訟法》在2022年1月4日實施，原大法官全體審查會與憲法法庭整 合並機關化，大法官解釋改稱為「憲法法庭判決」。下述何者錯誤？', '["以憲法法庭做出判決或裁定，而非大法官會議解釋處理憲法爭議", "維持大法官2/3人數出席，出席大法官人數2/3同意為通過", "增加「專家諮詢」及「法庭之友」制度", "憲法法庭裁判書必須公開，並記載參與大法官姓名及主筆者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:22+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00560', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-111-c655adf3', 'sub-diplomatic-456f2445-05', NULL, 'single_choice', '根據國際非政府組織「自由之家」（FreedomHouse）發布的《2021年世界自由度報告》評估報告 顯示，政府對COVID-19疫情大流行的反應，加劇了全球民主的衰落。下述何者錯誤？', '["對政府處理疫情的政策與措施，表示反對的人面臨騷擾或刑事指控", "專制政權和民粹主義領導人致力於降低疫情透明度，助長虛假或誤導性訊息的傳播", "執政者以疫情及防疫為掩護，削弱政治反對派，鞏固權力", "民主衰落主要集中在威權國家，民主國家並不受影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:22+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00561', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-111-c655adf3', 'sub-diplomatic-456f2445-05', NULL, 'single_choice', '網路民主（Internet Democracy）是指運用資通訊科技提升民主政治治理，但亦有促使網路民粹主義 （InternetPopulism）或政府網路監控審查（InternetCensorship）的爭議，下述何者錯誤？', '["網際網路產生了個人的、社會的及想像的網際權力（cyber power），掌握資通訊科技的菁英成為新 統治菁英", "由於網際網路使用的普及，當代網路輿論可說是展現全意志（generalwill）的民主政治", "網路民粹主義如同傳統民粹主義，反對菁英主義，但卻又造就新菁英", "政府監控審查網際網路言論，仍須依據憲法保障言論自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:22+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL)
